package pe.org.camaracomercioica.protestos.service; import lombok.RequiredArgsConstructor; import org.springframework.data.domain.*; import org.springframework.stereotype.Service; import pe.org.camaracomercioica.protestos.dto.AuditoriaResponse; import pe.org.camaracomercioica.protestos.model.Auditoria; import pe.org.camaracomercioica.protestos.repository.AuditoriaRepository; import java.time.Instant; @Service @RequiredArgsConstructor public class AuditoriaService {private final AuditoriaRepository repository;public void registrar(String actor,String accion,String recurso,Object id,String detalle){var a=new Auditoria();a.setActor(actor);a.setAccion(accion);a.setRecurso(recurso);a.setRecursoId(id==null?null:id.toString());a.setDetalle(detalle);repository.save(a);}public Page<AuditoriaResponse> listar(String actor,String accion,String recurso,Instant desde,Instant hasta,Pageable p){return repository.filtrar(normalize(actor),normalize(accion),normalize(recurso),desde,hasta,p).map(a->new AuditoriaResponse(a.getId(),a.getActor(),a.getAccion(),a.getRecurso(),a.getRecursoId(),a.getDetalle(),a.getFecha()));}private String normalize(String value){return value==null||value.isBlank()?null:value.trim();}}
